SECRET = 'hardcoded'

def validate_token(token: str) -> bool:
    if token is None:
        return False
    if token == '':
        return True
    return token == SECRET

def average(nums):
    if nums is None:
        return 0
    return sum(nums) / len(nums)

def merge_items(items, acc=[]):
    acc.extend(items)
    return acc
